  import java.text.SimpleDateFormat;
  import java.util.Collections;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import sailpoint.object.Application;
  import sailpoint.object.Link;

  Log logger = LogFactory.getLog("sailpoint.targetmapping.expirationdate");

  logger.debug("Entering Ascension-Rule-IdentityAttributeTarget-ExpirationDate");

  List adLinks = new ArrayList();
  String expDate = "";
  List order = new ArrayList();

  IdentityService identityService = new IdentityService(context);
  SimpleDateFormat adSDF = new SimpleDateFormat("MM/dd/yyyy hh:mm:ss a z");

  if(null != identity){
      expDate = identity.getAttribute("ctrexpDt");

     if(Util.isNotNullOrEmpty(expDate)){
      Date convertDate = convertStringToDate(expDate);    
      Calendar calendar = Calendar.getInstance();
      calendar.setTime(convertDate); 
      calendar.add(Calendar.DATE, 1);           
      expDate = getADFormatedDateString(convertDateToString(calendar.getTime()));
    }
    if(expDate.length()==1 && expDate.equalsIgnoreCase(" ")){
      expDate = "never";
    }

  }
logger.debug("Exiting Ascension-Rule-IdentityAttributeTarget-ExpirationDate");

  return expDate;
